const fs = require('fs');
const path = require('path');
const files = {
  "src/app/contractors/[slug]/page.tsx": ``,
  "src/app/blog/[slug]/page.tsx": ``,
  "src/app/services/[service-slug]/page.tsx": ``,
  "src/app/[state]/page.tsx": ``,
  "src/app/[state]/[city]/page.tsx": ``,
  "src/app/[state]/[city]/[service]/page.tsx": ``,
};
Object.entries(files).forEach(([filePath, b64]) => {
  const fullPath = path.join(process.cwd(), filePath);
  const dir = path.dirname(fullPath);
  fs.mkdirSync(dir, { recursive: true });
  const content = Buffer.from(b64, 'base64').toString('utf-8');
  fs.writeFileSync(fullPath, content, 'utf-8');
  console.log('Wrote:', filePath);
});
console.log('\n✅ Patch v23 applied — Schema components wired into all pages');
console.log('\nPages updated:');
